/**
 * Deploy YieldVault to all configured chains.
 *
 * Usage:
 *   pnpm --filter @workspace/scripts run deploy-yield
 *
 * Reads from environment:
 *   DEPLOYER_PRIVATE_KEY  — deployer wallet private key (needs gas on each chain)
 *
 * APYs (simulated testnet rates, set to incentivize rebalancing to Arc):
 *   Arc Testnet    — 18.5% (1850 bps)
 *   Base Sepolia   — 12.3% (1230 bps)
 *   Avalanche Fuji —  9.2%  (920 bps)
 *   Eth Sepolia    —  7.8%  (780 bps)
 */

import { ethers } from "ethers";
import { writeFileSync, mkdirSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));

const ABI = [
  "constructor(address _usdc, uint256 _apyBps, string _vaultName)",
  "function apyBps() view returns (uint256)",
  "function vaultName() view returns (string)",
  "function totalDeposited() view returns (uint256)",
  "function currentValue(address) view returns (uint256)",
  "function pendingYield(address) view returns (uint256)",
  "function positions(address) view returns (uint256 principal, uint256 checkpointYield, uint256 lastTimestamp)",
  "function deposit(uint256 amount)",
  "function withdraw() returns (uint256 received)",
  "function setApy(uint256 newApyBps)",
  "function fundVault(uint256 amount)",
  "function rescueTokens(address token, address to, uint256 amount)",
  "event Deposited(address indexed user, uint256 amount, uint256 newPrincipal)",
  "event Withdrawn(address indexed user, uint256 principal, uint256 yieldPaid, uint256 total)",
];

// Compiled from contracts/YieldVault.sol (solc 0.8.20, optimizer 200 runs)
const BYTECODE =
  "";

interface ChainTarget {
  name: string;
  rpcUrl: string;
  chainId: number;
  explorerUrl: string;
  usdc: string;
  apyBps: number;
  vaultLabel: string;
}

const CHAINS: ChainTarget[] = [
  {
    name: "Arc Testnet",
    rpcUrl: "https://rpc.drpc.testnet.arc.network",
    chainId: 5042002,
    explorerUrl: "https://testnet.arcscan.app",
    usdc: "0x3600000000000000000000000000000000000000",
    apyBps: 1850,   // 18.5%
    vaultLabel: "Arc Yield Vault",
  },
  {
    name: "Ethereum Sepolia",
    rpcUrl: "https://ethereum-sepolia-rpc.publicnode.com",
    chainId: 11155111,
    explorerUrl: "https://sepolia.etherscan.io",
    usdc: "0x1c7D4B196Cb0C7B01d743Fbc6116a902379C7238",
    apyBps: 780,    // 7.8%
    vaultLabel: "Sepolia Yield Vault",
  },
  {
    name: "Base Sepolia",
    rpcUrl: "https://sepolia.base.org",
    chainId: 84532,
    explorerUrl: "https://sepolia.basescan.org",
    usdc: "0x036CbD53842c5426634e7929541eC2318f3dCF7e",
    apyBps: 1230,   // 12.3%
    vaultLabel: "Base Yield Vault",
  },
  {
    name: "Avalanche Fuji",
    rpcUrl: "https://api.avax-test.network/ext/bc/C/rpc",
    chainId: 43113,
    explorerUrl: "https://testnet.snowtrace.io",
    usdc: "0x5425890298aed601595a70AB815c96711a31Bc65",
    apyBps: 920,    // 9.2%
    vaultLabel: "Fuji Yield Vault",
  },
];

async function deployToChain(
  chain: ChainTarget,
  privateKey: string
): Promise<string> {
  console.log(`\n📡 Connecting to ${chain.name} (chainId ${chain.chainId})...`);

  const provider = new ethers.JsonRpcProvider(chain.rpcUrl);
  const wallet   = new ethers.Wallet(privateKey, provider);
  const address  = await wallet.getAddress();
  const balance  = await provider.getBalance(address);

  console.log(`   Deployer : ${address}`);
  console.log(`   Balance  : ${ethers.formatEther(balance)} native`);
  console.log(`   USDC     : ${chain.usdc}`);
  console.log(`   APY      : ${chain.apyBps / 100}% (${chain.apyBps} bps)`);

  if (balance === 0n) {
    throw new Error(
      `No native balance on ${chain.name}. Fund the deployer wallet with testnet gas first.`
    );
  }

  const network = await provider.getNetwork();
  if (Number(network.chainId) !== chain.chainId) {
    throw new Error(`Chain ID mismatch: expected ${chain.chainId}, got ${network.chainId}`);
  }

  const factory  = new ethers.ContractFactory(ABI, BYTECODE, wallet);
  console.log(`   Deploying YieldVault ("${chain.vaultLabel}")...`);

  const contract = await factory.deploy(chain.usdc, chain.apyBps, chain.vaultLabel);
  const deployed = await contract.waitForDeployment();
  const addr     = await deployed.getAddress();

  const explorerLink = chain.explorerUrl
    ? `${chain.explorerUrl}/address/${addr}`
    : addr;
  console.log(`   ✅ Address  : ${addr}`);
  console.log(`   🔍 Explorer : ${explorerLink}`);

  return addr;
}

async function main() {
  const privateKey = process.env.DEPLOYER_PRIVATE_KEY;
  if (!privateKey) throw new Error("DEPLOYER_PRIVATE_KEY secret is not set.");

  console.log("🌱 YieldVault Deployment");
  console.log("════════════════════════════════════════════════");

  const deployments: Record<string, { address: string; apyBps: number; vaultLabel: string }> = {};
  const failed: string[] = [];

  for (const chain of CHAINS) {
    try {
      const addr = await deployToChain(chain, privateKey);
      deployments[chain.chainId.toString()] = {
        address: addr,
        apyBps: chain.apyBps,
        vaultLabel: chain.vaultLabel,
      };
    } catch (err) {
      console.error(`\n❌ Failed on ${chain.name}: ${(err as Error).message}`);
      failed.push(chain.name);
    }
  }

  const outDir  = resolve(__dirname, "../../artifacts/arc-bridge/src/contracts");
  const outFile = resolve(outDir, "yieldVaultDeployments.json");
  mkdirSync(outDir, { recursive: true });
  writeFileSync(outFile, JSON.stringify({ deployments }, null, 2));

  console.log("\n════════════════════════════════════════════════");
  console.log("📄 YieldVault Deployment Summary");
  for (const [chainId, info] of Object.entries(deployments)) {
    const chain = CHAINS.find((c) => c.chainId.toString() === chainId);
    console.log(`   ${(chain?.name ?? chainId).padEnd(22)} ${info.address}  (${info.apyBps / 100}% APY)`);
  }

  if (failed.length > 0) {
    console.log(`\n⚠️  Failed chains: ${failed.join(", ")}`);
    process.exit(1);
  }

  console.log(`\n✅ Saved to: ${outFile}`);
}

main().catch((err) => {
  console.error("\n💥 Fatal:", err.message);
  process.exit(1);
});
